BullMQ

```typescript
import { Queue, Worker } from "bullmq";

import sharp from "sharp";

// 1. Set up connection + queue

const connection = { host: "localhost", port: 6379 };

const imageQueue = new Queue("image-processing", { connection });

// 2. Add job

await imageQueue.add("process", {

  imageUrl: "https://example.com/photo.jpg",

  width: 800,

});

// 3. Create worker (separate process recommended)

const worker = new Worker(

  "image-processing",

  async (job) => {

    const response = await fetch(job.data.imageUrl);

    const buffer = Buffer.from(await response.arrayBuffer());

    const optimized = await sharp(buffer)

      .resize(job.data.width)

      .webp({ quality: 80 })

      .toBuffer();

    // Upload to S3, return URL...

    return { size: optimized.length };

  },

  { connection, concurrency: 5 }

);

worker.on("failed", (job, err) => {

  console.error(`Job ${job?.id} failed: ${err.message}`);

});
```

